function facetFunctionSelectors(
    address facet_
) public view returns (bytes4[] memory selectors_) {
    EnumerableSet.Bytes32Set storage _f2s = _getDiamondStorage().facetToSelectors[facet_];

    selectors_ = new bytes4[](_f2s.length());

    for (uint256 i = 0; i < selectors_.length; ++i) {
        selectors_[i] = bytes4(_f2s.at(i));
    }
}

function countPrefixes(
    uint256[] memory arr_
) internal pure returns (uint256[] memory prefixes_) {
    if (arr_.length == 0) {
        return prefixes_;
    }

    prefixes_ = new uint256[](arr_.length);
    prefixes_[0] = arr_[0];

    for (uint256 i = 1; i < prefixes_.length; ++i) {
        prefixes_[i] = prefixes_[i - 1] + arr_[i];
    }
}

function formatCuint(uint64 value_) internal pure returns (bytes memory) {
    if (value_ < 0xfd) {
        return abi.encodePacked(uint8(value_));
    }

    if (value_ <= 0xffff) {
        return abi.encodePacked(uint8(0xfd), uint16(value_).uint16BEtoLE());
    }

    if (value_ <= 0xffffffff) {
        return abi.encodePacked(uint8(0xfe), uint32(value_).uint32BEtoLE());
    }

    return abi.encodePacked(uint8(0xff), value_.uint64BEtoLE());
}

function modexpU256(uint512 b_, uint256 e_, uint512 m_) internal view returns (uint512 r_) {
    unchecked {
        r_ = uint512.wrap(_allocate(_UINT512_ALLOCATION));
        call512 call_ = initCall();

        _modexpU256(call_, b_, e_, m_, r_);
    }
}

function _add(uint512 a_, uint512 b_, uint512 r_) private pure {
    unchecked {
        assembly {
            let aWord_ := mload(add(a_, 0x20))
            let sum_ := add(aWord_, mload(add(b_, 0x20)))

            mstore(add(r_, 0x20), sum_)

            sum_ := gt(aWord_, sum_)
            sum_ := add(sum_, add(mload(a_), mload(b_)))

            mstore(r_, sum_)
        }
    }
}

function _sub(uint512 a_, uint512 b_, uint512 r_) private pure {
    unchecked {
        assembly {
            let aWord_ := mload(add(a_, 0x20))
            let diff_ := sub(aWord_, mload(add(b_, 0x20)))

            mstore(add(r_, 0x20), diff_)

            diff_ := gt(diff_, aWord_)
            diff_ := sub(sub(mload(a_), mload(b_)), diff_)

            mstore(r_, diff_)
        }
    }
}

function _and(uint512 a_, uint512 b_, uint512 r_) private pure {
    unchecked {
        assembly {
            mstore(r_, and(mload(a_), mload(b_)))
            mstore(add(r_, 0x20), and(mload(add(a_, 0x20)), mload(add(b_, 0x20))))
        }
    }
}

function _xor(uint512 a_, uint512 b_, uint512 r_) private pure {
    unchecked {
        assembly {
            mstore(r_, xor(mload(a_), mload(b_)))
            mstore(add(r_, 0x20), xor(mload(add(a_, 0x20)), mload(add(b_, 0x20))))
        }
    }
}

function powu(UD60x18 x, uint256 y) pure returns (UD60x18 result) {
    // Calculate the first iteration of the loop in advance.
    uint256 xUint = x.unwrap();
    uint256 resultUint = y & 1 > 0 ? xUint : uUNIT;

    // Equivalent to `for(y /= 2; y > 0; y /= 2)`.
    for (y >>= 1; y > 0; y >>= 1) {
        xUint = Common.mulDiv18(xUint, xUint);

        // Equivalent to `y % 2 == 1`.
        if (y & 1 > 0) {
            resultUint = Common.mulDiv18(resultUint, xUint);
        }
    }
    result = wrap(resultUint);
}
